import java.lang.annotation.*;

// @Target: Restricting applicable targets
// ElementType.TYPE → classes, interfaces, enums
// ElementType.METHOD → methods
// ElementType.FIELD → fields
// ElementType.PARAMETER → parameters
// ElementType.CONSTRUCTOR → constructors
// ElementType.LOCAL_VARIABLE → local variables

// @Retention: Retention policy
// RetentionPolicy.SOURCE → source code only (discarded after compilation)
// RetentionPolicy.CLASS → retained in class file (default)
// RetentionPolicy.RUNTIME → accessible at runtime via reflection

@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
@interface MyAnnotation {
    String value();
}

