import java.lang.annotation.*;

// Marker annotation (no elements)
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Test {}

// Single-value annotation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Author {
    String value();  // Can omit element name when using if named value
}

// Multi-element annotation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Todo {
    String description();
    String assignee() default "未定";
    int priority() default 3;
}

// Usage examples
@Author("Taro")  // Element name can be omitted for value()
// MyApp class definition
class MyApp {
    @Test
    // testMethod method definition
    void testMethod() {}

    @Todo(description = "実装する", priority = 1)
    // futureMethod method definition
    void futureMethod() {}
}

import java.lang.annotation.*;

// Elements with various types
@Retention(RetentionPolicy.RUNTIME)
@interface Config {
    int count() default 10;           // Primitive type
    String name();                     // String
    Class<?> type() default Object.class; // Class
    DayOfWeek day() default DayOfWeek.MONDAY; // Enum type
    Author author();                   // Annotation type
    String[] tags() default {};        // Array
}

// Using array elements
@interface Roles {
    String[] value();
}

// Curly braces can be omitted for single-element arrays
@Roles("admin")
// Same as @Roles({"admin"})
class AdminService {}

@Roles({"admin", "manager"})
