import java.lang.annotation.*;

// 1. A repeatable annotation
@Repeatable(Roles.class)  // Specify the container
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Role {
    String value();
}

// 2. Container annotation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Roles {
    Role[] value();  // Array of the repeatable annotation
}

// 3. Usage: Applying the same annotation multiple times
@Role("admin")
@Role("manager")
@Role("user")
// MultiRoleUser class definition
class MultiRoleUser {
}

// Can also be written directly with the container annotation
@Roles({@Role("admin"), @Role("manager")})
// AnotherUser class definition
class AnotherUser {
}

import java.lang.annotation.*;
import java.lang.reflect.Method;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Info {
    String author();
    String date();
}

// Service class definition
class Service {
    @Info(author = "Taro", date = "2024-04-01")
    // process method definition
    public void process() {
        System.out.println("処理実行");
    }

    // other method definition
    public void other() {}
}

// Retrieving annotations via reflection
// Main class definition
public class Main {
    public static void main(String[] args) throws Exception {
        Method method = Service.class.getMethod("process");

        // Check for annotation presence
        // Conditional branching
        if (method.isAnnotationPresent(Info.class)) {
            Info info = method.getAnnotation(Info.class);
            System.out.println("作者: " + info.author());
            System.out.println("日付: " + info.date());
        }
        // Output:
        // 作者: Taro
        // 日付: 2024-04-01

        // Retrieve all annotations
        Annotation[] anns = method.getAnnotations();
        // Enhanced for loop (processes all elements of a collection in order)
        for (Annotation a : anns) {
            System.out.println(a);
        }
    }
}

import java.lang.annotation.*;

// Retrieving @Repeatable annotations
// MultiRoleUser annotated with @Role("admin") @Role("manager")

Class<?> clazz = MultiRoleUser.class;

// Method 1: Direct retrieval with getAnnotationsByType()
Role[] roles = clazz.getAnnotationsByType(Role.class);
for (Role r : roles) {
    System.out.println(r.value());
}
// admin
// manager
// user

// Method 2: Via the container annotation
Roles container = clazz.getAnnotation(Roles.class);
if (container != null) {
    for (Role r : container.value()) {
        System.out.println(r.value());
    }
}

